#ifndef _YFS_H_
#define _YFS_H_

#include <comp421/filesystem.h>
#include <comp421/iolib.h>

#define YFS_OPEN        1
#define YFS_CLOSE       2
#define YFS_CREATE      3
#define YFS_READ        4
#define YFS_WRITE       5
#define YFS_SEEK        6
#define YFS_LINK        7
#define YFS_UNLINK      8
#define YFS_SYMLINK     9
#define YFS_READLINK    10
#define YFS_MKDIR       11
#define YFS_RMDIR       12
#define YFS_CHDIR       13
#define YFS_STAT        14
#define YFS_SYNC        15
#define YFS_SHUTDOWN    16

struct yfs_msg {
    int type;
    int inum;
    int reuse;
    int val1;
    int val2;
    void *ptr1;
    void *ptr2;
};
/* 
 * Wait, the above struct is:
 * type (4) + inum (4) + reuse (4) + val1 (4) + val2 (4) + ptr1 (8) + ptr2 (8) = 36 bytes.
 * Still too big. Let's optimize.
 */

struct yfs_request {
    int type;
    int inum;           /* Also used for curr_dir_inum or fd in some cases */
    int reuse;
    int val1;           /* size, path_len, offset, whence, etc. */
    int val2;           /* path2_len, etc. */
    void *ptr1;         /* pathname, buffer, etc. */
    /* 4 + 4 + 4 + 4 + 4 + 8 = 28 bytes. 4 more to reach 32. */
    int pad;
};

/* Let's try another one for two-pointer ops like Link */
struct yfs_request_2ptr {
    int type;
    int inum;
    int val1;
    int val2;
    void *ptr1;
    void *ptr2;
};
/* 4 + 4 + 4 + 4 + 8 + 8 = 32 bytes! This is perfect. */

/* Union to hold different request types */
typedef union {
    struct {
        int type;
        int inum;
        int reuse;
        int val1;
        int val2;
        void *ptr1;
        int pad;
    } common;
    struct {
        int type;
        int inum;
        int val1;
        int val2;
        void *ptr1;
        void *ptr2;
    } two_ptr;
    char padding[32];
} yfs_msg_t;

#endif /* _YFS_H_ */

#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <string.h>
#include <stdlib.h>
#include "yfs.h"

struct fd_entry {
    int inum;
    int reuse;
    int pos;
    int is_used;
    int is_dir;
};

static struct fd_entry fd_table[MAX_OPEN_FILES];
static int curr_dir_inum = ROOTINODE;
static int initialized = 0;

static void init_iolib() {
    if (!initialized) {
        int i;
        for (i = 0; i < MAX_OPEN_FILES; i++) {
            fd_table[i].is_used = 0;
        }
        curr_dir_inum = ROOTINODE;
        initialized = 1;
    }
}

int Open(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_OPEN;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].is_used) {
            fd_table[i].inum = msg.common.inum;
            fd_table[i].reuse = msg.common.reuse;
            fd_table[i].pos = 0;
            fd_table[i].is_used = 1;
            fd_table[i].is_dir = msg.common.val2; /* Server should return if it's a dir */
            return i;
        }
    }
    return ERROR;
}

int Close(int fd) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;

    fd_table[fd].is_used = 0;
    return 0;
}

int Create(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_CREATE;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].is_used) {
            fd_table[i].inum = msg.common.inum;
            fd_table[i].reuse = msg.common.reuse;
            fd_table[i].pos = 0;
            fd_table[i].is_used = 1;
            fd_table[i].is_dir = 0; /* Created file is never a directory */
            return i;
        }
    }
    return ERROR;
}

int Read(int fd, void *buf, int size) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_READ;
    msg.common.inum = fd_table[fd].inum;
    msg.common.reuse = fd_table[fd].reuse;
    msg.common.val1 = size;
    msg.common.val2 = fd_table[fd].pos;
    msg.common.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    fd_table[fd].pos += msg.common.val1;
    return msg.common.val1;
}

int Write(int fd, void *buf, int size) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;
    if (fd_table[fd].is_dir) return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_WRITE;
    msg.common.inum = fd_table[fd].inum;
    msg.common.reuse = fd_table[fd].reuse;
    msg.common.val1 = size;
    msg.common.val2 = fd_table[fd].pos;
    msg.common.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    fd_table[fd].pos += msg.common.val1;
    return msg.common.val1;
}

int Seek(int fd, int offset, int whence) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_SEEK;
    msg.common.inum = fd_table[fd].inum;
    msg.common.reuse = fd_table[fd].reuse;
    msg.common.val1 = offset;
    msg.common.val2 = whence;
    msg.common.pad = fd_table[fd].pos; /* Send current pos just in case */

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    fd_table[fd].pos = msg.common.val1;
    return msg.common.val1;
}

int Link(char *oldname, char *newname) {
    init_iolib();
    if (oldname == NULL || newname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.two_ptr.type = YFS_LINK;
    msg.two_ptr.inum = curr_dir_inum;
    msg.two_ptr.val1 = strlen(oldname);
    msg.two_ptr.val2 = strlen(newname);
    msg.two_ptr.ptr1 = oldname;
    msg.two_ptr.ptr2 = newname;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.two_ptr.type == ERROR) return ERROR;
    return 0;
}

int Unlink(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_UNLINK;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;
    return 0;
}

int SymLink(char *oldname, char *newname) {
    init_iolib();
    if (oldname == NULL || newname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.two_ptr.type = YFS_SYMLINK;
    msg.two_ptr.inum = curr_dir_inum;
    msg.two_ptr.val1 = strlen(oldname);
    msg.two_ptr.val2 = strlen(newname);
    msg.two_ptr.ptr1 = oldname;
    msg.two_ptr.ptr2 = newname;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.two_ptr.type == ERROR) return ERROR;
    return 0;
}

int ReadLink(char *pathname, char *buf, int len) {
    init_iolib();
    if (pathname == NULL || buf == NULL || len < 0) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_READLINK;
    msg.common.inum = curr_dir_inum;
    msg.common.val1 = strlen(pathname);
    msg.common.val2 = len;
    msg.common.ptr1 = pathname;
    msg.common.pad = (long)buf; /* Not ideal, but we need to pass buf to server */

    /* Wait, pad is only 4 bytes. ptr1 is 8 bytes.
     * Let's use two_ptr for this too.
     */
    msg.two_ptr.type = YFS_READLINK;
    msg.two_ptr.inum = curr_dir_inum;
    msg.two_ptr.val1 = strlen(pathname);
    msg.two_ptr.val2 = len;
    msg.two_ptr.ptr1 = pathname;
    msg.two_ptr.ptr2 = buf;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.two_ptr.type == ERROR) return ERROR;
    return msg.two_ptr.val1;
}

int MkDir(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_MKDIR;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;
    return 0;
}

int RmDir(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_RMDIR;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;
    return 0;
}

int ChDir(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_CHDIR;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    curr_dir_inum = msg.common.inum;
    return 0;
}

int Stat(char *pathname, struct Stat *statbuf) {
    init_iolib();
    if (pathname == NULL || statbuf == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.two_ptr.type = YFS_STAT;
    msg.two_ptr.inum = curr_dir_inum;
    msg.two_ptr.val1 = strlen(pathname);
    msg.two_ptr.ptr1 = pathname;
    msg.two_ptr.ptr2 = statbuf;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.two_ptr.type == ERROR) return ERROR;
    return 0;
}

int Sync(void) {
    init_iolib();
    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_SYNC;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;
    return 0;
}

int Shutdown(void) {
    init_iolib();
    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_SHUTDOWN;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;
    return 0;
}

#ifndef _CACHE_H_
#define _CACHE_H_

#include <comp421/filesystem.h>
#include "yfs.h"

struct cache_block {
    int blocknum;
    char data[BLOCKSIZE];
    int dirty;
    struct cache_block *next, *prev;
    struct cache_block *hash_next;
};

struct cache_inode {
    int inum;
    struct inode inode;
    int dirty;
    struct cache_inode *next, *prev;
    struct cache_inode *hash_next;
};

void init_cache();
struct cache_block *get_block(int blocknum);
void release_block(struct cache_block *cb); /* Not strictly needed if we don't have pins */
struct cache_inode *get_inode(int inum);
void release_inode(struct cache_inode *ci);
void sync_cache();

#endif /* _CACHE_H_ */

#include <comp421/yalnix.h>
#include <string.h>
#include <stdlib.h>
#include "cache.h"

#define HASH_SIZE 8

static struct cache_block block_cache[BLOCK_CACHESIZE];
static struct cache_block *block_lru_head = NULL, *block_lru_tail = NULL;
static struct cache_block *block_hash[HASH_SIZE];

static struct cache_inode inode_cache[INODE_CACHESIZE];
static struct cache_inode *inode_lru_head = NULL, *inode_lru_tail = NULL;
static struct cache_inode *inode_hash[HASH_SIZE];

/* Inode to block mapping constants */
extern int NUM_INODES;
extern int NUM_BLOCKS;

static int block_hash_fn(int blocknum) { return blocknum % HASH_SIZE; }
static int inode_hash_fn(int inum) { return inum % HASH_SIZE; }

static void write_block_to_disk(struct cache_block *cb) {
    if (cb->dirty) {
        WriteSector(cb->blocknum, cb->data);
        cb->dirty = 0;
    }
}

static void write_inode_to_block_cache(struct cache_inode *ci) {
    if (ci->dirty) {
        int blocknum = 1 + (ci->inum / INODES_PER_BLOCK);
        int offset = (ci->inum % INODES_PER_BLOCK) * INODESIZE;
        struct cache_block *cb = get_block(blocknum);
        if (cb) {
            memcpy(cb->data + offset, &ci->inode, INODESIZE);
            cb->dirty = 1;
            ci->dirty = 0;
        }
    }
}

void init_cache() {
    int i;
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        block_cache[i].blocknum = -1;
        block_cache[i].dirty = 0;
        block_cache[i].next = (i + 1 < BLOCK_CACHESIZE) ? &block_cache[i+1] : NULL;
        block_cache[i].prev = (i > 0) ? &block_cache[i-1] : NULL;
        block_cache[i].hash_next = NULL;
    }
    block_lru_head = &block_cache[0];
    block_lru_tail = &block_cache[BLOCK_CACHESIZE - 1];
    memset(block_hash, 0, sizeof(block_hash));

    for (i = 0; i < INODE_CACHESIZE; i++) {
        inode_cache[i].inum = -1;
        inode_cache[i].dirty = 0;
        inode_cache[i].next = (i + 1 < INODE_CACHESIZE) ? &inode_cache[i+1] : NULL;
        inode_cache[i].prev = (i > 0) ? &inode_cache[i-1] : NULL;
        inode_cache[i].hash_next = NULL;
    }
    inode_lru_head = &inode_cache[0];
    inode_lru_tail = &inode_cache[INODE_CACHESIZE - 1];
    memset(inode_hash, 0, sizeof(inode_hash));
}

static void move_to_head_block(struct cache_block *cb) {
    if (cb == block_lru_head) return;
    if (cb->prev) cb->prev->next = cb->next;
    if (cb->next) cb->next->prev = cb->prev;
    if (cb == block_lru_tail) block_lru_tail = cb->prev;
    cb->next = block_lru_head;
    cb->prev = NULL;
    if (block_lru_head) block_lru_head->prev = cb;
    block_lru_head = cb;
}

struct cache_block *get_block(int blocknum) {
    if (blocknum < 0 || blocknum >= NUM_BLOCKS) return NULL;

    int h = block_hash_fn(blocknum);
    struct cache_block *cb = block_hash[h];
    while (cb) {
        if (cb->blocknum == blocknum) {
            move_to_head_block(cb);
            return cb;
        }
        cb = cb->hash_next;
    }

    /* Not in cache, evict tail */
    cb = block_lru_tail;
    if (cb->blocknum != -1) {
        /* Remove from hash */
        int old_h = block_hash_fn(cb->blocknum);
        struct cache_block **prev_ptr = &block_hash[old_h];
        while (*prev_ptr && *prev_ptr != cb) prev_ptr = &((*prev_ptr)->hash_next);
        if (*prev_ptr) *prev_ptr = cb->hash_next;
        write_block_to_disk(cb);
    }

    cb->blocknum = blocknum;
    cb->dirty = 0;
    ReadSector(blocknum, cb->data);

    /* Add to hash */
    cb->hash_next = block_hash[h];
    block_hash[h] = cb;

    move_to_head_block(cb);
    return cb;
}

static void move_to_head_inode(struct cache_inode *ci) {
    if (ci == inode_lru_head) return;
    if (ci->prev) ci->prev->next = ci->next;
    if (ci->next) ci->next->prev = ci->prev;
    if (ci == inode_lru_tail) inode_lru_tail = ci->prev;
    ci->next = inode_lru_head;
    ci->prev = NULL;
    if (inode_lru_head) inode_lru_head->prev = ci;
    inode_lru_head = ci;
}

struct cache_inode *get_inode(int inum) {
    if (inum <= 0 || inum > NUM_INODES) return NULL;

    int h = inode_hash_fn(inum);
    struct cache_inode *ci = inode_hash[h];
    while (ci) {
        if (ci->inum == inum) {
            move_to_head_inode(ci);
            return ci;
        }
        ci = ci->hash_next;
    }

    /* Not in cache, evict tail */
    ci = inode_lru_tail;
    if (ci->inum != -1) {
        /* Remove from hash */
        int old_h = inode_hash_fn(ci->inum);
        struct cache_inode **prev_ptr = &inode_hash[old_h];
        while (*prev_ptr && *prev_ptr != ci) prev_ptr = &((*prev_ptr)->hash_next);
        if (*prev_ptr) *prev_ptr = ci->hash_next;
        write_inode_to_block_cache(ci);
    }

    ci->inum = inum;
    ci->dirty = 0;

    int blocknum = 1 + (inum / INODES_PER_BLOCK);
    int offset = (inum % INODES_PER_BLOCK) * INODESIZE;
    struct cache_block *cb = get_block(blocknum);
    if (cb) {
        memcpy(&ci->inode, cb->data + offset, INODESIZE);
    } else {
        return NULL;
    }

    /* Add to hash */
    ci->hash_next = inode_hash[h];
    inode_hash[h] = ci;

    move_to_head_inode(ci);
    return ci;
}

void sync_cache() {
    int i;
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (inode_cache[i].inum != -1) {
            write_inode_to_block_cache(&inode_cache[i]);
        }
    }
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (block_cache[i].blocknum != -1) {
            write_block_to_disk(&block_cache[i]);
        }
    }
}

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>
#include "yfs.h"
#include "cache.h"

int NUM_INODES;
int NUM_BLOCKS;
int FIRST_DATA_BLOCK;

static char block_bitmap[NUMSECTORS / 8 + 1];
static char inode_bitmap[1024 / 8 + 1]; /* Assuming max 1024 inodes */

/* Helper to manage bitmasks */
static void set_bit(char *bitmap, int bit) {
    bitmap[bit / 8] |= (1 << (bit % 8));
}
static void clear_bit(char *bitmap, int bit) {
    bitmap[bit / 8] &= ~(1 << (bit % 8));
}
static int get_bit(char *bitmap, int bit) {
    return (bitmap[bit / 8] >> (bit % 8)) & 1;
}

/* Free list management */
static int alloc_inode() {
    int i;
    for (i = 1; i <= NUM_INODES; i++) {
        if (!get_bit(inode_bitmap, i)) {
            set_bit(inode_bitmap, i);
            struct cache_inode *ci = get_inode(i);
            ci->inode.reuse++;
            ci->dirty = 1;
            return i;
        }
    }
    return ERROR;
}

static void free_inode(int inum) {
    if (inum <= 0 || inum > NUM_INODES) return;
    struct cache_inode *ci = get_inode(inum);
    if (ci) {
        ci->inode.type = INODE_FREE;
        ci->dirty = 1;
    }
    clear_bit(inode_bitmap, inum);
}

static int alloc_block() {
    int i;
    for (i = FIRST_DATA_BLOCK; i < NUM_BLOCKS; i++) {
        if (!get_bit(block_bitmap, i)) {
            set_bit(block_bitmap, i);
            /* Zero out the new block */
            struct cache_block *cb = get_block(i);
            if (cb) {
                memset(cb->data, 0, BLOCKSIZE);
                cb->dirty = 1;
            }
            return i;
        }
    }
    return ERROR;
}

static void free_block(int blocknum) {
    if (blocknum < FIRST_DATA_BLOCK || blocknum >= NUM_BLOCKS) return;
    clear_bit(block_bitmap, blocknum);
}

/* Forward declarations of handlers */
static void handle_open(int pid, yfs_msg_t *msg);
static void handle_create(int pid, yfs_msg_t *msg);
static void handle_read(int pid, yfs_msg_t *msg);
static void handle_write(int pid, yfs_msg_t *msg);
static void handle_seek(int pid, yfs_msg_t *msg);
static void handle_link(int pid, yfs_msg_t *msg);
static void handle_unlink(int pid, yfs_msg_t *msg);
static void handle_symlink(int pid, yfs_msg_t *msg);
static void handle_readlink(int pid, yfs_msg_t *msg);
static void handle_mkdir(int pid, yfs_msg_t *msg);
static void handle_rmdir(int pid, yfs_msg_t *msg);
static void handle_chdir(int pid, yfs_msg_t *msg);
static void handle_stat(int pid, yfs_msg_t *msg);

int main(int argc, char **argv) {
    /* Initialize file system info from super block */
    char buf[SECTORSIZE];
    if (ReadSector(1, buf) == ERROR) {
        fprintf(stderr, "Failed to read super block\n");
        Exit(1);
    }
    struct fs_header *header = (struct fs_header *)buf;
    NUM_BLOCKS = header->num_blocks;
    NUM_INODES = header->num_inodes;
    FIRST_DATA_BLOCK = 1 + (NUM_INODES + INODES_PER_BLOCK - 1 + 1) / INODES_PER_BLOCK;
    /* Wait, the formula in instructions: 1 + ceil((num_inodes + 1) / INODES_PER_BLOCK) 
     * If num_inodes = 47, (47+1)/8 = 6. 1 + 6 = 7. Correct.
     */
    FIRST_DATA_BLOCK = 1 + (NUM_INODES + 1 + INODES_PER_BLOCK - 1) / INODES_PER_BLOCK;

    init_cache();
    memset(block_bitmap, 0, sizeof(block_bitmap));
    memset(inode_bitmap, 0, sizeof(inode_bitmap));

    /* Scan inodes to build bitmaps */
    int i, j;
    for (i = 1; i <= NUM_INODES; i++) {
        struct cache_inode *ci = get_inode(i);
        if (ci->inode.type != INODE_FREE) {
            set_bit(inode_bitmap, i);
            /* Mark its blocks as used */
            for (j = 0; j < NUM_DIRECT; j++) {
                if (ci->inode.direct[j] != 0) {
                    set_bit(block_bitmap, ci->inode.direct[j]);
                }
            }
            if (ci->inode.indirect != 0) {
                set_bit(block_bitmap, ci->inode.indirect);
                struct cache_block *cb = get_block(ci->inode.indirect);
                int *indirect_blocks = (int *)cb->data;
                for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) {
                    if (indirect_blocks[j] != 0) {
                        set_bit(block_bitmap, indirect_blocks[j]);
                    }
                }
            }
        }
    }

    if (Register(FILE_SERVER) == ERROR) {
        fprintf(stderr, "Failed to register file server\n");
        Exit(1);
    }

    /* Start first client */
    if (argc > 1) {
        int pid = Fork();
        if (pid == 0) {
            Exec(argv[1], argv + 1);
            fprintf(stderr, "Failed to exec %s\n", argv[1]);
            Exit(1);
        }
    }

    /* Main loop */
    while (1) {
        yfs_msg_t msg;
        int sender_pid = Receive(&msg);
        if (sender_pid == 0) break;
        if (sender_pid == ERROR) continue;

        switch (msg.common.type) {
            case YFS_OPEN: handle_open(sender_pid, &msg); break;
            case YFS_CREATE: handle_create(sender_pid, &msg); break;
            case YFS_READ: handle_read(sender_pid, &msg); break;
            case YFS_WRITE: handle_write(sender_pid, &msg); break;
            case YFS_SEEK: handle_seek(sender_pid, &msg); break;
            case YFS_LINK: handle_link(sender_pid, &msg); break;
            case YFS_UNLINK: handle_unlink(sender_pid, &msg); break;
            case YFS_SYMLINK: handle_symlink(sender_pid, &msg); break;
            case YFS_READLINK: handle_readlink(sender_pid, &msg); break;
            case YFS_MKDIR: handle_mkdir(sender_pid, &msg); break;
            case YFS_RMDIR: handle_rmdir(sender_pid, &msg); break;
            case YFS_CHDIR: handle_chdir(sender_pid, &msg); break;
            case YFS_STAT: handle_stat(sender_pid, &msg); break;
            case YFS_SYNC: sync_cache(); Reply(&msg, sender_pid); break;
            case YFS_SHUTDOWN: 
                sync_cache(); 
                printf("YFS server shutting down\n");
                Reply(&msg, sender_pid);
                Exit(0);
            default:
                msg.common.type = ERROR;
                Reply(&msg, sender_pid);
        }
    }
    return 0;
}

