/* Directory entry lookup */
static int find_in_dir(int dir_inum, char *name, int name_len) {
    if (name_len > DIRNAMELEN) return 0;

    struct cache_inode *ci = get_inode(dir_inum);
    if (!ci || ci->inode.type != INODE_DIRECTORY) return 0;

    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;

        if (block_idx < NUM_DIRECT) {
            blocknum = ci->inode.direct[block_idx];
        } else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            int *indirect_blocks = (int *)icb->data;
            blocknum = indirect_blocks[block_idx - NUM_DIRECT];
        }

        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum != 0) {
            int match = 0;
            if (name_len == DIRNAMELEN) {
                if (strncmp(de->name, name, DIRNAMELEN) == 0) match = 1;
            } else {
                if (strncmp(de->name, name, name_len) == 0 && (de->name[name_len] == '\0' || name_len == DIRNAMELEN)) match = 1;
            }
            if (match) return de->inum;
        }
    }
    return 0;
}

/* Path resolution */
static int resolve_path(int pid, int curr_dir_inum, char *path, int path_len, int *parent_inum, char *last_component) {
    if (path_len <= 0) return ERROR;

    char local_path[MAXPATHNAMELEN];
    if (CopyFrom(pid, local_path, path, path_len) == ERROR) return ERROR;
    local_path[path_len] = '\0';

    int inum = (local_path[0] == '/') ? ROOTINODE : curr_dir_inum;
    char *token = strtok(local_path, "/");
    int next_inum;

    if (parent_inum) *parent_inum = inum;

    while (token != NULL) {
        char *next_token = strtok(NULL, "/");
        if (next_token == NULL) {
            /* This is the last component */
            if (last_component) {
                strncpy(last_component, token, DIRNAMELEN);
                if (strlen(token) < DIRNAMELEN) last_component[strlen(token)] = '\0';
            }
            if (parent_inum) *parent_inum = inum;
            next_inum = find_in_dir(inum, token, strlen(token));
            return next_inum ? next_inum : ERROR;
        }

        next_inum = find_in_dir(inum, token, strlen(token));
        if (!next_inum) return ERROR;

        inum = next_inum;
        token = next_token;
    }

    /* Path was just "/" or empty after tokens */
    if (local_path[0] == '/') {
        if (last_component) strcpy(last_component, ".");
        if (parent_inum) *parent_inum = inum;
        return ROOTINODE;
    }

    return ERROR;
}

