/* Truncate inode: free all data blocks */
static void truncate_inode(struct cache_inode *ci) {
    int i, j;
    /* Free direct blocks */
    for (i = 0; i < NUM_DIRECT; i++) {
        if (ci->inode.direct[i] != 0) {
            free_block(ci->inode.direct[i]);
            ci->inode.direct[i] = 0;
        }
    }
    /* Free indirect blocks */
    if (ci->inode.indirect != 0) {
        struct cache_block *cb = get_block(ci->inode.indirect);
        if (cb) {
            int *indirect_blocks = (int *)cb->data;
            for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) {
                if (indirect_blocks[j] != 0) {
                    free_block(indirect_blocks[j]);
                }
            }
        }
        free_block(ci->inode.indirect);
        ci->inode.indirect = 0;
    }
    ci->inode.size = 0;
    ci->dirty = 1;
}

/* Add entry to directory */
static int add_to_dir(int dir_inum, int inum, char *name) {
    struct cache_inode *ci = get_inode(dir_inum);
    if (!ci || ci->inode.type != INODE_DIRECTORY) return ERROR;

    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    struct dir_entry *de = NULL;
    int found_free = 0;
    int target_block = 0;
    int target_offset = 0;

    /* Search for a free entry */
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;

        if (block_idx < NUM_DIRECT) {
            blocknum = ci->inode.direct[block_idx];
        } else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            int *indirect_blocks = (int *)icb->data;
            blocknum = indirect_blocks[block_idx - NUM_DIRECT];
        }

        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        de = (struct dir_entry *)(cb->data + offset);
        if (de->inum == 0) {
            found_free = 1;
            target_block = blocknum;
            target_offset = offset;
            break;
        }
    }

    if (!found_free) {
        /* Append new entry */
        int new_entry_idx = num_entries;
        int block_idx = (new_entry_idx * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (new_entry_idx * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;

        if (block_idx < NUM_DIRECT) {
            if (ci->inode.direct[block_idx] == 0) {
                ci->inode.direct[block_idx] = alloc_block();
                if (ci->inode.direct[block_idx] == ERROR) return ERROR;
            }
            blocknum = ci->inode.direct[block_idx];
        } else {
            if (ci->inode.indirect == 0) {
                ci->inode.indirect = alloc_block();
                if (ci->inode.indirect == ERROR) return ERROR;
            }
            struct cache_block *icb = get_block(ci->inode.indirect);
            int *indirect_blocks = (int *)icb->data;
            if (indirect_blocks[block_idx - NUM_DIRECT] == 0) {
                indirect_blocks[block_idx - NUM_DIRECT] = alloc_block();
                if (indirect_blocks[block_idx - NUM_DIRECT] == ERROR) return ERROR;
                icb->dirty = 1;
            }
            blocknum = indirect_blocks[block_idx - NUM_DIRECT];
        }
        target_block = blocknum;
        target_offset = offset;
        ci->inode.size += sizeof(struct dir_entry);
        ci->dirty = 1;
    }

    struct cache_block *cb = get_block(target_block);
    de = (struct dir_entry *)(cb->data + target_offset);
    de->inum = inum;
    strncpy(de->name, name, DIRNAMELEN);
    cb->dirty = 1;
    return 0;
}

static void handle_open(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL);
    if (inum == ERROR) {
        msg->common.type = ERROR;
    } else {
        struct cache_inode *ci = get_inode(inum);
        msg->common.inum = inum;
        msg->common.reuse = ci->inode.reuse;
        msg->common.val2 = (ci->inode.type == INODE_DIRECTORY);
    }
    Reply(msg, pid);
}

static void handle_create(int pid, yfs_msg_t *msg) {
    int parent_inum;
    char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component);

    if (inum != ERROR) {
        /* Already exists */
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type == INODE_DIRECTORY) {
            msg->common.type = ERROR;
        } else {
            truncate_inode(ci);
            msg->common.inum = inum;
            msg->common.reuse = ci->inode.reuse;
        }
    } else {
        /* Create new */
        struct cache_inode *pci = get_inode(parent_inum);
        if (!pci || pci->inode.type != INODE_DIRECTORY) {
            msg->common.type = ERROR;
        } else {
            int new_inum = alloc_inode();
            if (new_inum == ERROR) {
                msg->common.type = ERROR;
            } else {
                struct cache_inode *nci = get_inode(new_inum);
                nci->inode.type = INODE_REGULAR;
                nci->inode.nlink = 1;
                nci->inode.size = 0;
                memset(nci->inode.direct, 0, sizeof(nci->inode.direct));
                nci->inode.indirect = 0;
                nci->dirty = 1;

                if (add_to_dir(parent_inum, new_inum, last_component) == ERROR) {
                    free_inode(new_inum);
                    msg->common.type = ERROR;
                } else {
                    msg->common.inum = new_inum;
                    msg->common.reuse = nci->inode.reuse;
                }
            }
        }
    }
    Reply(msg, pid);
}

