/* Get disk block number for a given byte offset in an inode */
static int get_block_for_offset(struct cache_inode *ci, int offset, int alloc) {
    int block_idx = offset / BLOCKSIZE;
    if (block_idx < NUM_DIRECT) {
        if (ci->inode.direct[block_idx] == 0 && alloc) {
            ci->inode.direct[block_idx] = alloc_block();
            if (ci->inode.direct[block_idx] != ERROR) ci->dirty = 1;
        }
        return ci->inode.direct[block_idx];
    } else {
        block_idx -= NUM_DIRECT;
        if (block_idx >= (int)(BLOCKSIZE / sizeof(int))) return ERROR;

        if (ci->inode.indirect == 0) {
            if (!alloc) return 0;
            ci->inode.indirect = alloc_block();
            if (ci->inode.indirect == ERROR) return ERROR;
            ci->dirty = 1;
        }
        struct cache_block *icb = get_block(ci->inode.indirect);
        int *indirect_blocks = (int *)icb->data;
        if (indirect_blocks[block_idx] == 0 && alloc) {
            indirect_blocks[block_idx] = alloc_block();
            if (indirect_blocks[block_idx] != ERROR) icb->dirty = 1;
        }
        return indirect_blocks[block_idx];
    }
}

static void handle_read(int pid, yfs_msg_t *msg) {
    int inum = msg->common.inum;
    int reuse = msg->common.reuse;
    int size = msg->common.val1;
    int pos = msg->common.val2;
    void *buf = msg->common.ptr1;

    struct cache_inode *ci = get_inode(inum);
    if (!ci || ci->inode.reuse != reuse) {
        msg->common.type = ERROR;
        Reply(msg, pid);
        return;
    }

    if (pos >= ci->inode.size) {
        msg->common.val1 = 0;
        Reply(msg, pid);
        return;
    }

    if (pos + size > ci->inode.size) {
        size = ci->inode.size - pos;
    }

    int bytes_read = 0;
    while (bytes_read < size) {
        int curr_pos = pos + bytes_read;
        int blocknum = get_block_for_offset(ci, curr_pos, 0);
        int offset = curr_pos % BLOCKSIZE;
        int to_read = BLOCKSIZE - offset;
        if (to_read > size - bytes_read) to_read = size - bytes_read;

        if (blocknum == 0) {
            /* Hole: return zeros */
            char zeros[BLOCKSIZE];
            memset(zeros, 0, to_read);
            if (CopyTo(pid, (char *)buf + bytes_read, zeros, to_read) == ERROR) {
                msg->common.type = ERROR;
                Reply(msg, pid);
                return;
            }
        } else if (blocknum == ERROR) {
            msg->common.type = ERROR;
            Reply(msg, pid);
            return;
        } else {
            struct cache_block *cb = get_block(blocknum);
            if (CopyTo(pid, (char *)buf + bytes_read, cb->data + offset, to_read) == ERROR) {
                msg->common.type = ERROR;
                Reply(msg, pid);
                return;
            }
        }
        bytes_read += to_read;
    }

    msg->common.val1 = bytes_read;
    Reply(msg, pid);
}

static void handle_write(int pid, yfs_msg_t *msg) {
    int inum = msg->common.inum;
    int reuse = msg->common.reuse;
    int size = msg->common.val1;
    int pos = msg->common.val2;
    void *buf = msg->common.ptr1;

    struct cache_inode *ci = get_inode(inum);
    if (!ci || ci->inode.reuse != reuse || ci->inode.type == INODE_DIRECTORY) {
        msg->common.type = ERROR;
        Reply(msg, pid);
        return;
    }

    int bytes_written = 0;
    while (bytes_written < size) {
        int curr_pos = pos + bytes_written;
        int blocknum = get_block_for_offset(ci, curr_pos, 1);
        if (blocknum == ERROR || blocknum == 0) {
            msg->common.type = ERROR;
            Reply(msg, pid);
            return;
        }

        int offset = curr_pos % BLOCKSIZE;
        int to_write = BLOCKSIZE - offset;
        if (to_write > size - bytes_written) to_write = size - bytes_written;

        struct cache_block *cb = get_block(blocknum);
        if (CopyFrom(pid, cb->data + offset, (char *)buf + bytes_written, to_write) == ERROR) {
            msg->common.type = ERROR;
            Reply(msg, pid);
            return;
        }
        cb->dirty = 1;
        bytes_written += to_write;
    }

    if (pos + bytes_written > ci->inode.size) {
        ci->inode.size = pos + bytes_written;
        ci->dirty = 1;
    }

    msg->common.val1 = bytes_written;
    Reply(msg, pid);
}

