static void handle_seek(int pid, yfs_msg_t *msg) {
    int inum = msg->common.inum;
    int reuse = msg->common.reuse;
    int offset = msg->common.val1;
    int whence = msg->common.val2;
    int curr_pos = msg->common.pad;

    struct cache_inode *ci = get_inode(inum);
    if (!ci || ci->inode.reuse != reuse) {
        msg->common.type = ERROR;
    } else {
        int new_pos;
        if (whence == SEEK_SET) new_pos = offset;
        else if (whence == SEEK_CUR) new_pos = curr_pos + offset;
        else if (whence == SEEK_END) new_pos = ci->inode.size + offset;
        else {
            msg->common.type = ERROR;
            Reply(msg, pid);
            return;
        }

        if (new_pos < 0) {
            msg->common.type = ERROR;
        } else {
            msg->common.val1 = new_pos;
        }
    }
    Reply(msg, pid);
}

static void handle_stat(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL);
    if (inum == ERROR) {
        msg->two_ptr.type = ERROR;
    } else {
        struct cache_inode *ci = get_inode(inum);
        struct Stat statbuf;
        statbuf.inum = inum;
        statbuf.type = ci->inode.type;
        statbuf.size = ci->inode.size;
        statbuf.nlink = ci->inode.nlink;
        if (CopyTo(pid, msg->two_ptr.ptr2, &statbuf, sizeof(struct Stat)) == ERROR) {
            msg->two_ptr.type = ERROR;
        }
    }
    Reply(msg, pid);
}

static void handle_chdir(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL);
    if (inum == ERROR) {
        msg->common.type = ERROR;
    } else {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type != INODE_DIRECTORY) {
            msg->common.type = ERROR;
        } else {
            msg->common.inum = inum;
        }
    }
    Reply(msg, pid);
}

static void handle_mkdir(int pid, yfs_msg_t *msg) {
    int parent_inum;
    char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component);

    if (inum != ERROR) {
        msg->common.type = ERROR;
    } else {
        struct cache_inode *pci = get_inode(parent_inum);
        if (!pci || pci->inode.type != INODE_DIRECTORY) {
            msg->common.type = ERROR;
        } else {
            int new_inum = alloc_inode();
            if (new_inum == ERROR) {
                msg->common.type = ERROR;
            } else {
                struct cache_inode *nci = get_inode(new_inum);
                nci->inode.type = INODE_DIRECTORY;
                nci->inode.nlink = 2; /* . and parent's entry */
                nci->inode.size = 0;
                memset(nci->inode.direct, 0, sizeof(nci->inode.direct));
                nci->inode.indirect = 0;
                nci->dirty = 1;

                if (add_to_dir(new_inum, new_inum, ".") == ERROR ||
                    add_to_dir(new_inum, parent_inum, "..") == ERROR ||
                    add_to_dir(parent_inum, new_inum, last_component) == ERROR) {
                    /* Should really cleanup here */
                    msg->common.type = ERROR;
                } else {
                    pci->inode.nlink++;
                    pci->dirty = 1;
                    msg->common.inum = new_inum;
                }
            }
        }
    }
    Reply(msg, pid);
}

static int is_dir_empty(int inum) {
    struct cache_inode *ci = get_inode(inum);
    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;
        if (block_idx < NUM_DIRECT) blocknum = ci->inode.direct[block_idx];
        else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
        }
        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum != 0 && strcmp(de->name, ".") != 0 && strcmp(de->name, "..") != 0) {
            return 0;
        }
    }
    return 1;
}

static void handle_rmdir(int pid, yfs_msg_t *msg) {
    int parent_inum;
    char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component);

    if (inum == ERROR || inum == ROOTINODE || strcmp(last_component, ".") == 0 || strcmp(last_component, "..") == 0) {
        msg->common.type = ERROR;
    } else {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type != INODE_DIRECTORY || !is_dir_empty(inum)) {
            msg->common.type = ERROR;
        } else {
            /* Remove from parent */
            struct cache_inode *pci = get_inode(parent_inum);
            int num_entries = pci->inode.size / sizeof(struct dir_entry);
            int i;
            for (i = 0; i < num_entries; i++) {
                int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
                int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
                int blocknum = 0;
                if (block_idx < NUM_DIRECT) blocknum = pci->inode.direct[block_idx];
                else {
                    struct cache_block *icb = get_block(pci->inode.indirect);
                    blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
                }
