        } else {
            int parent_inum;
            char last_component[DIRNAMELEN + 1];
            int new_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &parent_inum, last_component);
            if (new_inum != ERROR) {
                msg->two_ptr.type = ERROR;
            } else {
                if (add_to_dir(parent_inum, old_inum, last_component) == ERROR) {
                    msg->two_ptr.type = ERROR;
