static void handle_symlink(int pid, yfs_msg_t *msg) {
    int parent_inum;
    char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &parent_inum, last_component);

    if (inum != ERROR) {
        msg->two_ptr.type = ERROR;
    } else {
        int new_inum = alloc_inode();
        if (new_inum == ERROR) {
            msg->two_ptr.type = ERROR;
        } else {
            struct cache_inode *nci = get_inode(new_inum);
            nci->inode.type = INODE_SYMLINK;
            nci->inode.nlink = 1;
            nci->inode.size = msg->two_ptr.val1;
            memset(nci->inode.direct, 0, sizeof(nci->inode.direct));
            nci->inode.indirect = 0;
            nci->dirty = 1;

            /* Write symlink target to file */
            int bytes_written = 0;
            char target[MAXPATHNAMELEN];
            CopyFrom(pid, target, msg->two_ptr.ptr1, msg->two_ptr.val1);

            while (bytes_written < msg->two_ptr.val1) {
                int blocknum = get_block_for_offset(nci, bytes_written, 1);
                int offset = bytes_written % BLOCKSIZE;
                int to_write = BLOCKSIZE - offset;
                if (to_write > msg->two_ptr.val1 - bytes_written) to_write = msg->two_ptr.val1 - bytes_written;
                struct cache_block *cb = get_block(blocknum);
                memcpy(cb->data + offset, target + bytes_written, to_write);
                cb->dirty = 1;
                bytes_written += to_write;
            }

            if (add_to_dir(parent_inum, new_inum, last_component) == ERROR) {
                truncate_inode(nci);
                free_inode(new_inum);
                msg->two_ptr.type = ERROR;
            }
        }
    }
    Reply(msg, pid);
}

