static int is_dir_empty(int inum) {
    struct cache_inode *ci = get_inode(inum);
    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;
        if (block_idx < NUM_DIRECT) blocknum = ci->inode.direct[block_idx];
        else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
        }
        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum != 0 && !is_dot(de->name) && !is_dotdot(de->name)) {
            return 0;
        }
    }
    return 1;
}

static void handle_rmdir(int pid, yfs_msg_t *msg) {
    int parent_inum;
    char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component, 0);

    if (inum == ERROR || inum == ROOTINODE || is_dot(last_component) || is_dotdot(last_component)) {
        msg->common.type = ERROR;
    } else {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type != INODE_DIRECTORY || !is_dir_empty(inum)) {
            msg->common.type = ERROR;
        } else {
            /* Remove from parent */
            struct cache_inode *pci = get_inode(parent_inum);
            int num_entries = pci->inode.size / sizeof(struct dir_entry);
            int i;
            for (i = 0; i < num_entries; i++) {
                int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
                int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
                int blocknum = 0;
                if (block_idx < NUM_DIRECT) blocknum = pci->inode.direct[block_idx];
                else {
                    struct cache_block *icb = get_block(pci->inode.indirect);
                    blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
                }
                struct cache_block *cb = get_block(blocknum);
                struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
                if (de->inum == inum) {
                    de->inum = 0;
                    cb->dirty = 1;
                    break;
                }
            }
            pci->inode.nlink--;
            pci->dirty = 1;
            truncate_inode(ci);
            free_inode(inum);
        }
    }
    Reply(msg, pid);
}

