static char block_bitmap[NUMSECTORS / 8 + 1];
static char inode_bitmap[1024 / 8 + 1]; /* Assuming max 1024 inodes */

/* Helper to manage bitmasks */
static void set_bit(char *bitmap, int bit) {
    bitmap[bit / 8] |= (1 << (bit % 8));
}
static void clear_bit(char *bitmap, int bit) {
    bitmap[bit / 8] &= ~(1 << (bit % 8));
}
static int get_bit(char *bitmap, int bit) {
    return (bitmap[bit / 8] >> (bit % 8)) & 1;
}

