/* Helper to check for . and .. */
static int is_dot(char *name) {
    if (name[0] != '.') return 0;
    if (DIRNAMELEN > 1 && name[1] != '\0') return 0;
    return 1;
}
static int is_dotdot(char *name) {
    if (name[0] != '.' || name[1] != '.') return 0;
    if (DIRNAMELEN > 2 && name[2] != '\0') return 0;
    return 1;
}

/* Directory entry lookup */
static int find_in_dir(int dir_inum, char *name, int name_len) {
    if (name_len > DIRNAMELEN) return 0;

    struct cache_inode *ci = get_inode(dir_inum);
    if (!ci || ci->inode.type != INODE_DIRECTORY) return 0;

    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;

        if (block_idx < NUM_DIRECT) {
            blocknum = ci->inode.direct[block_idx];
        } else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            int *indirect_blocks = (int *)icb->data;
            blocknum = indirect_blocks[block_idx - NUM_DIRECT];
        }

        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum != 0) {
            int match = 0;
            if (name_len == DIRNAMELEN) {
                if (strncmp(de->name, name, DIRNAMELEN) == 0) match = 1;
            } else {
                if (strncmp(de->name, name, name_len) == 0 && (name_len == DIRNAMELEN || de->name[name_len] == '\0')) match = 1;
            }
            if (match) return de->inum;
        }
    }
    return 0;
}

/* Get disk block number for a given byte offset in an inode */
static int get_block_for_offset(struct cache_inode *ci, int offset, int alloc) {
    int block_idx = offset / BLOCKSIZE;
    if (block_idx < NUM_DIRECT) {
        if (ci->inode.direct[block_idx] == 0 && alloc) {
            ci->inode.direct[block_idx] = alloc_block();
            if (ci->inode.direct[block_idx] != ERROR) ci->dirty = 1;
        }
        return ci->inode.direct[block_idx];
    } else {
        block_idx -= NUM_DIRECT;
        if (block_idx >= (int)(BLOCKSIZE / sizeof(int))) return ERROR;

        if (ci->inode.indirect == 0) {
            if (!alloc) return 0;
            ci->inode.indirect = alloc_block();
            if (ci->inode.indirect == ERROR) return ERROR;
            ci->dirty = 1;
        }
        struct cache_block *icb = get_block(ci->inode.indirect);
        int *indirect_blocks = (int *)icb->data;
        if (indirect_blocks[block_idx] == 0 && alloc) {
            indirect_blocks[block_idx] = alloc_block();
            if (indirect_blocks[block_idx] != ERROR) icb->dirty = 1;
        }
        return indirect_blocks[block_idx];
    }
}

static int resolve_path_internal(int pid, int curr_dir_inum, char *path, int *parent_inum, char *last_component, int symlink_depth, int follow_last);

static int resolve_symlink(int pid, int dir_inum, int sym_inum, int symlink_depth) {
    if (symlink_depth >= MAXSYMLINKS) return ERROR;

    struct cache_inode *ci = get_inode(sym_inum);
    if (!ci || ci->inode.type != INODE_SYMLINK) return ERROR;

    char target[MAXPATHNAMELEN];
    int to_read = ci->inode.size;
    if (to_read >= MAXPATHNAMELEN) to_read = MAXPATHNAMELEN - 1;

    int bytes_read = 0;
    while (bytes_read < to_read) {
        int blocknum = get_block_for_offset(ci, bytes_read, 0);
        int offset = bytes_read % BLOCKSIZE;
        int n = BLOCKSIZE - offset;
        if (n > to_read - bytes_read) n = to_read - bytes_read;
        struct cache_block *cb = get_block(blocknum);
        memcpy(target + bytes_read, cb->data + offset, n);
        bytes_read += n;
    }
    target[to_read] = '\0';

    return resolve_path_internal(pid, dir_inum, target, NULL, NULL, symlink_depth + 1, 1);
}

static int resolve_path_internal(int pid, int curr_dir_inum, char *path, int *parent_inum, char *last_component, int symlink_depth, int follow_last) {
    if (path == NULL || path[0] == '\0') return ERROR;

    int inum = (path[0] == '/') ? ROOTINODE : curr_dir_inum;
    if (parent_inum) *parent_inum = inum;
    if (last_component) strcpy(last_component, ".");

    char path_copy[MAXPATHNAMELEN];
    strncpy(path_copy, path, MAXPATHNAMELEN);
    path_copy[MAXPATHNAMELEN-1] = '\0';

    char *curr = path_copy;
    while (*curr == '/') curr++;

    while (*curr != '\0') {
        char *next = strchr(curr, '/');
        if (next) *next = '\0';

        if (parent_inum) *parent_inum = inum;
        if (last_component) {
            strncpy(last_component, curr, DIRNAMELEN);
            if (strlen(curr) < DIRNAMELEN) last_component[strlen(curr)] = '\0';
        }

        int next_inum = find_in_dir(inum, curr, strlen(curr));
        if (!next_inum) {
            char *peek = next ? next + 1 : NULL;
            while (peek && *peek == '/') peek++;
            if (next == NULL || peek == NULL || *peek == '\0') {
                if (parent_inum) *parent_inum = inum;
                if (last_component) {
                    strncpy(last_component, curr, DIRNAMELEN);
                    if (strlen(curr) < DIRNAMELEN) last_component[strlen(curr)] = '\0';
                }
                return 0;
            }
            return ERROR;
        }

        struct cache_inode *next_ci = get_inode(next_inum);
        if (next_ci->inode.type == INODE_SYMLINK) {
            int is_last = (next == NULL);
            if (!is_last) {
                char *peek = next + 1;
                while (*peek == '/') peek++;
                if (*peek == '\0') is_last = 1;
            }
            if (!is_last || follow_last) {
                next_inum = resolve_symlink(pid, inum, next_inum, symlink_depth);
                if (next_inum == ERROR) return ERROR;
            }
        }

        if (next != NULL) {
            char *peek = next + 1;
            while (*peek == '/') peek++;
            if (*peek != '\0') {
                struct cache_inode *ci = get_inode(next_inum);
                if (ci->inode.type != INODE_DIRECTORY) return ERROR;
                inum = next_inum;
                curr = peek;
            } else {
                inum = next_inum;
                break;
            }
        } else {
            inum = next_inum;
            break;
        }
    }
    return inum;
}

static int resolve_path(int pid, int curr_dir_inum, char *path, int path_len, int *parent_inum, char *last_component, int follow_last) {
    char local_path[MAXPATHNAMELEN];
    if (path_len >= MAXPATHNAMELEN) path_len = MAXPATHNAMELEN - 1;
    if (CopyFrom(pid, local_path, path, path_len) == ERROR) return ERROR;
    local_path[path_len] = '\0';

    if (path_len > 1 && local_path[path_len-1] == '/') {
        if (path_len + 1 < MAXPATHNAMELEN) {
            local_path[path_len] = '.';
            local_path[path_len+1] = '\0';
        }
    }
    return resolve_path_internal(pid, curr_dir_inum, local_path, parent_inum, last_component, 0, follow_last);
}

static void truncate_inode(struct cache_inode *ci) {
    int i, j;
    for (i = 0; i < NUM_DIRECT; i++) {
        if (ci->inode.direct[i] != 0) {
            free_block(ci->inode.direct[i]);
            ci->inode.direct[i] = 0;
        }
    }
    if (ci->inode.indirect != 0) {
        struct cache_block *cb = get_block(ci->inode.indirect);
        if (cb) {
            int *indirect_blocks = (int *)cb->data;
            for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) {
                if (indirect_blocks[j] != 0) free_block(indirect_blocks[j]);
            }
        }
        free_block(ci->inode.indirect);
        ci->inode.indirect = 0;
    }
    ci->inode.size = 0;
    ci->dirty = 1;
}

static int add_to_dir(int dir_inum, int inum, char *name) {
    struct cache_inode *ci = get_inode(dir_inum);
    if (!ci || ci->inode.type != INODE_DIRECTORY) return ERROR;

    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    int found_free = 0;
    int target_block = 0, target_offset = 0;

    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;
        if (block_idx < NUM_DIRECT) blocknum = ci->inode.direct[block_idx];
        else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
        }
        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum == 0) {
            found_free = 1; target_block = blocknum; target_offset = offset;
            break;
        }
    }

    if (!found_free) {
        int block_idx = (num_entries * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (num_entries * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;
        if (block_idx < NUM_DIRECT) {
            if (ci->inode.direct[block_idx] == 0) {
                ci->inode.direct[block_idx] = alloc_block();
                if (ci->inode.direct[block_idx] == ERROR) return ERROR;
            }
            blocknum = ci->inode.direct[block_idx];
        } else {
            if (ci->inode.indirect == 0) {
                ci->inode.indirect = alloc_block();
                if (ci->inode.indirect == ERROR) return ERROR;
            }
            struct cache_block *icb = get_block(ci->inode.indirect);
            int *indirect_blocks = (int *)icb->data;
            if (indirect_blocks[block_idx - NUM_DIRECT] == 0) {
                indirect_blocks[block_idx - NUM_DIRECT] = alloc_block();
                if (indirect_blocks[block_idx - NUM_DIRECT] == ERROR) return ERROR;
                icb->dirty = 1;
            }
            blocknum = indirect_blocks[block_idx - NUM_DIRECT];
        }
        target_block = blocknum; target_offset = offset;
        ci->inode.size += sizeof(struct dir_entry);
        ci->dirty = 1;
    }

    struct cache_block *cb = get_block(target_block);
    struct dir_entry *de = (struct dir_entry *)(cb->data + target_offset);
    de->inum = inum;
    strncpy(de->name, name, DIRNAMELEN);
    cb->dirty = 1;
    return 0;
}

static int is_dir_empty(int inum) {
    struct cache_inode *ci = get_inode(inum);
    int num_entries = ci->inode.size / sizeof(struct dir_entry);
    int i;
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE;
        int offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE;
        int blocknum = 0;
        if (block_idx < NUM_DIRECT) blocknum = ci->inode.direct[block_idx];
        else {
            if (ci->inode.indirect == 0) break;
            struct cache_block *icb = get_block(ci->inode.indirect);
            blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
        }
        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum != 0 && !is_dot(de->name) && !is_dotdot(de->name)) return 0;
    }
    return 1;
}

static void handle_open(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL, 1);
    if (inum == ERROR || inum == 0) msg->common.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        msg->common.inum = inum; msg->common.reuse = ci->inode.reuse;
        msg->common.val2 = (ci->inode.type == INODE_DIRECTORY);
    }
    Reply(msg, pid);
}

static void handle_create(int pid, yfs_msg_t *msg) {
    int parent_inum; char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component, 1);
    if (inum != ERROR && inum != 0) {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type == INODE_DIRECTORY) msg->common.type = ERROR;
        else { truncate_inode(ci); msg->common.inum = inum; msg->common.reuse = ci->inode.reuse; }
    } else if (inum == 0) {
        struct cache_inode *pci = get_inode(parent_inum);
        if (!pci || pci->inode.type != INODE_DIRECTORY) msg->common.type = ERROR;
        else {
            int new_inum = alloc_inode();
            if (new_inum == ERROR) msg->common.type = ERROR;
            else {
                struct cache_inode *nci = get_inode(new_inum);
                nci->inode.type = INODE_REGULAR; nci->inode.nlink = 1; nci->inode.size = 0;
                memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
                if (add_to_dir(parent_inum, new_inum, last_component) == ERROR) { free_inode(new_inum); msg->common.type = ERROR; }
                else { msg->common.inum = new_inum; msg->common.reuse = nci->inode.reuse; }
            }
        }
    } else msg->common.type = ERROR;
    Reply(msg, pid);
}

static void handle_read(int pid, yfs_msg_t *msg) {
    struct cache_inode *ci = get_inode(msg->common.inum);
    if (!ci || ci->inode.reuse != msg->common.reuse) { msg->common.type = ERROR; Reply(msg, pid); return; }
    int pos = msg->common.val2, size = msg->common.val1;
    if (pos >= ci->inode.size) { msg->common.val1 = 0; Reply(msg, pid); return; }
    if (pos + size > ci->inode.size) size = ci->inode.size - pos;
    int bytes_read = 0;
    while (bytes_read < size) {
        int curr_pos = pos + bytes_read, blocknum = get_block_for_offset(ci, curr_pos, 0);
        int offset = curr_pos % BLOCKSIZE, to_read = BLOCKSIZE - offset;
        if (to_read > size - bytes_read) to_read = size - bytes_read;
        if (blocknum == 0) {
            char zeros[BLOCKSIZE]; memset(zeros, 0, to_read);
            if (CopyTo(pid, (char *)msg->common.ptr1 + bytes_read, zeros, to_read) == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; }
        } else {
            struct cache_block *cb = get_block(blocknum);
            if (CopyTo(pid, (char *)msg->common.ptr1 + bytes_read, cb->data + offset, to_read) == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; }
        }
        bytes_read += to_read;
    }
    msg->common.val1 = bytes_read; Reply(msg, pid);
}

static void handle_write(int pid, yfs_msg_t *msg) {
    struct cache_inode *ci = get_inode(msg->common.inum);
    if (!ci || ci->inode.reuse != msg->common.reuse || ci->inode.type == INODE_DIRECTORY) { msg->common.type = ERROR; Reply(msg, pid); return; }
    int pos = msg->common.val2, size = msg->common.val1, bytes_written = 0;
    while (bytes_written < size) {
        int curr_pos = pos + bytes_written, blocknum = get_block_for_offset(ci, curr_pos, 1);
        if (blocknum == ERROR || blocknum == 0) { msg->common.type = ERROR; Reply(msg, pid); return; }
        int offset = curr_pos % BLOCKSIZE, to_write = BLOCKSIZE - offset;
        if (to_write > size - bytes_written) to_write = size - bytes_written;
        struct cache_block *cb = get_block(blocknum);
        if (CopyFrom(pid, cb->data + offset, (char *)msg->common.ptr1 + bytes_written, to_write) == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; }
        cb->dirty = 1; bytes_written += to_write;
    }
    if (pos + bytes_written > ci->inode.size) { ci->inode.size = pos + bytes_written; ci->dirty = 1; }
    msg->common.val1 = bytes_written; Reply(msg, pid);
}

static void handle_seek(int pid, yfs_msg_t *msg) {
    struct cache_inode *ci = get_inode(msg->common.inum);
    if (!ci || ci->inode.reuse != msg->common.reuse) msg->common.type = ERROR;
    else {
        int new_pos;
        if (msg->common.val2 == SEEK_SET) new_pos = msg->common.val1;
        else if (msg->common.val2 == SEEK_CUR) new_pos = msg->common.pad + msg->common.val1;
        else if (msg->common.val2 == SEEK_END) new_pos = ci->inode.size + msg->common.val1;
        else { msg->common.type = ERROR; Reply(msg, pid); return; }
        if (new_pos < 0) msg->common.type = ERROR; else msg->common.val1 = new_pos;
    }
    Reply(msg, pid);
}

static void handle_stat(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
    if (inum == ERROR || inum == 0) msg->two_ptr.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum); struct Stat st;
        st.inum = inum; st.type = ci->inode.type; st.size = ci->inode.size; st.nlink = ci->inode.nlink;
        if (CopyTo(pid, msg->two_ptr.ptr2, &st, sizeof(struct Stat)) == ERROR) msg->two_ptr.type = ERROR;
    }
    Reply(msg, pid);
}

static void handle_chdir(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL, 1);
    if (inum == ERROR || inum == 0) msg->common.type = ERROR;
    else { if (get_inode(inum)->inode.type != INODE_DIRECTORY) msg->common.type = ERROR; else msg->common.inum = inum; }
    Reply(msg, pid);
}

static void handle_mkdir(int pid, yfs_msg_t *msg) {
    int parent_inum; char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component, 0);
    if (inum != ERROR && inum != 0) msg->common.type = ERROR;
    else if (inum == 0) {
        struct cache_inode *pci = get_inode(parent_inum);
        if (!pci || pci->inode.type != INODE_DIRECTORY) msg->common.type = ERROR;
        else {
            int new_inum = alloc_inode();
            if (new_inum == ERROR) msg->common.type = ERROR;
            else {
                struct cache_inode *nci = get_inode(new_inum);
                nci->inode.type = INODE_DIRECTORY; nci->inode.nlink = 2; nci->inode.size = 0;
                memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
                if (add_to_dir(new_inum, new_inum, ".") == ERROR || add_to_dir(new_inum, parent_inum, "..") == ERROR || add_to_dir(parent_inum, new_inum, last_component) == ERROR) msg->common.type = ERROR;
                else { pci->inode.nlink++; pci->dirty = 1; msg->common.inum = new_inum; }
            }
        }
    } else msg->common.type = ERROR;
    Reply(msg, pid);
}

static void handle_rmdir(int pid, yfs_msg_t *msg) {
    int parent_inum; char last_component[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &parent_inum, last_component, 0);
    if (inum == ERROR || inum == 0 || inum == ROOTINODE || is_dot(last_component) || is_dotdot(last_component)) msg->common.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type != INODE_DIRECTORY || !is_dir_empty(inum)) msg->common.type = ERROR;
        else {
            struct cache_inode *pci = get_inode(parent_inum);
            int num_entries = pci->inode.size / sizeof(struct dir_entry), i;
            for (i = 0; i < num_entries; i++) {
                int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE, blocknum = 0;
                if (block_idx < NUM_DIRECT) blocknum = pci->inode.direct[block_idx];
                else blocknum = ((int *)get_block(pci->inode.indirect)->data)[block_idx - NUM_DIRECT];
                struct cache_block *cb = get_block(blocknum); struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
                if (de->inum == inum) { de->inum = 0; cb->dirty = 1; break; }
            }
            pci->inode.nlink--; pci->dirty = 1; truncate_inode(ci); free_inode(inum);
        }
    }
    Reply(msg, pid);
}

static void handle_link(int pid, yfs_msg_t *msg) {
    int old_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
    if (old_inum == ERROR || old_inum == 0) msg->two_ptr.type = ERROR;
    else {
        struct cache_inode *oci = get_inode(old_inum);
        if (!oci || oci->inode.type == INODE_DIRECTORY) msg->two_ptr.type = ERROR;
        else {
            int p_inum; char last[DIRNAMELEN + 1];
            int n_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &p_inum, last, 0);
            if (n_inum != ERROR && n_inum != 0) msg->two_ptr.type = ERROR;
            else if (n_inum == 0) {
                if (add_to_dir(p_inum, old_inum, last) == ERROR) msg->two_ptr.type = ERROR;
                else { oci->inode.nlink++; oci->dirty = 1; }
            } else msg->two_ptr.type = ERROR;
        }
    }
    Reply(msg, pid);
}

static void handle_unlink(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &p_inum, last, 0);
    if (inum == ERROR || inum == 0) msg->common.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type == INODE_DIRECTORY) msg->common.type = ERROR;
        else {
            struct cache_inode *pci = get_inode(p_inum);
            int num = pci->inode.size / sizeof(struct dir_entry), i;
            for (i = 0; i < num; i++) {
                int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
                if (b_idx < NUM_DIRECT) bnum = pci->inode.direct[b_idx];
                else bnum = ((int *)get_block(pci->inode.indirect)->data)[b_idx - NUM_DIRECT];
                struct cache_block *cb = get_block(bnum); struct dir_entry *de = (struct dir_entry *)(cb->data + off);
                if (de->inum == inum) { de->inum = 0; cb->dirty = 1; break; }
            }
            ci->inode.nlink--; ci->dirty = 1; if (ci->inode.nlink == 0) { truncate_inode(ci); free_inode(inum); }
        }
    }
    Reply(msg, pid);
}

static void handle_symlink(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &p_inum, last, 0);
    if (inum != ERROR && inum != 0) msg->two_ptr.type = ERROR;
    else if (inum == 0) {
        int new_inum = alloc_inode();
        if (new_inum == ERROR) msg->two_ptr.type = ERROR;
        else {
            struct cache_inode *nci = get_inode(new_inum);
            nci->inode.type = INODE_SYMLINK; nci->inode.nlink = 1; nci->inode.size = msg->two_ptr.val1;
            memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
            char target[MAXPATHNAMELEN]; CopyFrom(pid, target, msg->two_ptr.ptr1, msg->two_ptr.val1);
            int bw = 0;
            while (bw < (int)msg->two_ptr.val1) {
                int bnum = get_block_for_offset(nci, bw, 1), off = bw % BLOCKSIZE, tw = BLOCKSIZE - off;
                if (tw > (int)msg->two_ptr.val1 - bw) tw = msg->two_ptr.val1 - bw;
                memcpy(get_block(bnum)->data + off, target + bw, tw); get_block(bnum)->dirty = 1; bw += tw;
            }
            if (add_to_dir(p_inum, new_inum, last) == ERROR) { truncate_inode(nci); free_inode(new_inum); msg->two_ptr.type = ERROR; }
        }
    } else msg->two_ptr.type = ERROR;
    Reply(msg, pid);
}

static void handle_readlink(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
    if (inum == ERROR || inum == 0) msg->two_ptr.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        if (ci->inode.type != INODE_SYMLINK) msg->two_ptr.type = ERROR;
        else {
            int tr = ci->inode.size; if (tr > msg->two_ptr.val2) tr = msg->two_ptr.val2;
            char target[MAXPATHNAMELEN]; int br = 0;
            while (br < tr) {
                int bnum = get_block_for_offset(ci, br, 0), off = br % BLOCKSIZE, n = BLOCKSIZE - off;
                if (n > tr - br) n = tr - br; memcpy(target + br, get_block(bnum)->data + off, n); br += n;
            }
            if (CopyTo(pid, msg->two_ptr.ptr2, target, tr) == ERROR) msg->two_ptr.type = ERROR;
            else msg->two_ptr.val1 = tr;
        }
    }
    Reply(msg, pid);
}

int main(int argc, char **argv) {
    char buf[SECTORSIZE]; if (ReadSector(1, buf) == ERROR) Exit(1);
    struct fs_header *header = (struct fs_header *)buf;
    NUM_BLOCKS = header->num_blocks; NUM_INODES = header->num_inodes;
    FIRST_DATA_BLOCK = 1 + (NUM_INODES + 1 + INODES_PER_BLOCK - 1) / INODES_PER_BLOCK;
    init_cache(); memset(block_bitmap, 0, sizeof(block_bitmap)); memset(inode_bitmap, 0, sizeof(inode_bitmap));
    int i, j;
    for (i = 1; i <= NUM_INODES; i++) {
        struct cache_inode *ci = get_inode(i);
        if (ci->inode.type != INODE_FREE) {
            set_bit(inode_bitmap, i);
            for (j = 0; j < NUM_DIRECT; j++) if (ci->inode.direct[j] != 0) set_bit(block_bitmap, ci->inode.direct[j]);
            if (ci->inode.indirect != 0) {
                set_bit(block_bitmap, ci->inode.indirect);
                int *ind = (int *)get_block(ci->inode.indirect)->data;
                for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) if (ind[j] != 0) set_bit(block_bitmap, ind[j]);
            }
        }
    }
    if (Register(FILE_SERVER) == ERROR) Exit(1);
    if (argc > 1) { int pid = Fork(); if (pid == 0) { Exec(argv[1], argv + 1); Exit(1); } }
    while (1) {
        yfs_msg_t msg; int sender_pid = Receive(&msg);
        if (sender_pid <= 0) break;
        switch (msg.common.type) {
            case YFS_OPEN: handle_open(sender_pid, &msg); break;
            case YFS_CREATE: handle_create(sender_pid, &msg); break;
            case YFS_READ: handle_read(sender_pid, &msg); break;
            case YFS_WRITE: handle_write(sender_pid, &msg); break;
            case YFS_SEEK: handle_seek(sender_pid, &msg); break;
            case YFS_LINK: handle_link(sender_pid, &msg); break;
            case YFS_UNLINK: handle_unlink(sender_pid, &msg); break;
            case YFS_SYMLINK: handle_symlink(sender_pid, &msg); break;
            case YFS_READLINK: handle_readlink(sender_pid, &msg); break;
            case YFS_MKDIR: handle_mkdir(sender_pid, &msg); break;
            case YFS_RMDIR: handle_rmdir(sender_pid, &msg); break;
            case YFS_CHDIR: handle_chdir(sender_pid, &msg); break;
            case YFS_STAT: handle_stat(sender_pid, &msg); break;
            case YFS_SYNC: sync_cache(); Reply(&msg, sender_pid); break;
            case YFS_SHUTDOWN: sync_cache(); printf("YFS server shutting down\n"); Reply(&msg, sender_pid); Exit(0);
            default: msg.common.type = ERROR; Reply(&msg, sender_pid);
        }
    }
    return 0;
}

