/* Helper to manage bitmasks */
static void set_bit(char *bitmap, int bit, int max_bits) {
    if (bit < 0 || bit >= max_bits) return;
    bitmap[bit / 8] |= (1 << (bit % 8));
}
static void clear_bit(char *bitmap, int bit, int max_bits) {
    if (bit < 0 || bit >= max_bits) return;
    bitmap[bit / 8] &= ~(1 << (bit % 8));
}
static int get_bit(char *bitmap, int bit, int max_bits) {
